{"operationName":"URE_FetchRecommendations","variables":{"placement":"pdp-ure","site":"dotcom-l","skuId":"6674708","relatedProductsCount":2,"additionalMinRelatedProductsCount":1,"groupIds":"","limit":15,"storeId":"1436","planPaidMembershipEffectiveType":"NULL","salesChannel":"LargeView","partyToken":"","userToken":"8217524d-4fb4-11f1-a701-0e79396342ad","visitorToken":"3161e7d0-5497-11f0-bd66-12204ace29a7","usePriceWithCart":true,"cartTimestamp":"1778519086907"},"extensions":{"clientLibrary":{"name":"@apollo/client","version":"4.1.6"}},"query":"query URE_FetchRecommendations($placement: String!, $site: String!, $skuId: String!, $relatedProductsCount: Int!, $additionalMinRelatedProductsCount: Int!, $groupIds: String!, $limit: Int!, $storeId: String!, $planPaidMembershipEffectiveType: String, $salesChannel: String!, $partyToken: String, $userToken: String, $visitorToken: String, $usePriceWithCart: Boolean!, $cartTimestamp: String!) {
  productBySkuId(skuId: $skuId) {
    whatItIs
    __typename
    skuId
    openBoxCondition
  }
  recommendationsByGroup(
    input: {placement: $placement, site: $site, skus: [$skuId], relatedProductsCount: $relatedProductsCount, additionalMinRelatedProductsCount: $additionalMinRelatedProductsCount, groupIds: $groupIds, limit: $limit, storeIds: [$storeId]}
    identity: {partyId: $partyToken, ut: $userToken, vt: $visitorToken}
  ) {
    id
    relatedGroups {
      title
      ...Subgroups
      __typename
    }
    relatedProducts {
      ...RelatedProducts
      __typename
    }
    __typename
  }
}

fragment Price on Product {
  price(
    input: {salesChannel: $salesChannel, planPaidMemberType: $planPaidMembershipEffectiveType, usePriceWithCart: $usePriceWithCart, cartTimestamp: $cartTimestamp, visitorId: $visitorToken, customerId: $userToken}
  ) {
    icrCode
    isMAP
    regularPrice
    currentPrice
    customerPrice
    totalSavings
    totalSavingsPercent
    preferredBadging
    strictMapIcr
    regularPriceMessageType
    saleEventMessageType
    __typename
  }
  __typename
  skuId
  openBoxCondition
}

fragment PrimaryImage on Product {
  primaryImage {
    piscesHref
    altText
    __typename
  }
  __typename
  skuId
  openBoxCondition
}

fragment Subgroups on RecommendationRelatedGroup {
  title
  subgroups {
    name
    id
    ep
    order
    skus
    item {
      ... on Product {
        skuId
        ...PrimaryImage
        __typename
        openBoxCondition
      }
      __typename
    }
    __typename
  }
  __typename
}

fragment RelatedProducts on RecommendationRelatedProduct {
  name
  id
  ep
  order
  recommendations {
    id
    ep
    rank
    item {
      ... on Product {
        name {
          short
          __typename
        }
        url {
          skuSpecificUrl
          relativePdp
          __typename
        }
        whatItIs
        skuId
        reviewInfo {
          reviewCount
          averageRating
          recommendedPercent
          __typename
        }
        ...PrimaryImage
        ...Price
        __typename
        openBoxCondition
      }
      __typename
    }
    __typename
  }
  __typename
}"}
